var accounts = pgTable("accounts", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  nameNormalized: text("name_normalized"),
  canonicalName: text("canonical_name"),
  // Dual-Industry Field Strategy (Phase 8)
  industryStandardized: text("industry_standardized"),
  industrySecondary: text("industry_secondary").array(),
  industryCode: text("industry_code"),
  industryRaw: text("industry_raw"),
  // AI Enrichment Fields
  industryAiSuggested: text("industry_ai_suggested"),
  industryAiCandidates: jsonb("industry_ai_candidates"),
  industryAiTopk: text("industry_ai_topk").array(),
  industryAiConfidence: numeric("industry_ai_confidence", { precision: 5, scale: 4 }),
  industryAiSource: text("industry_ai_source"),
  industryAiSuggestedAt: timestamp("industry_ai_suggested_at"),
  industryAiReviewedBy: varchar("industry_ai_reviewed_by").references(() => users.id, { onDelete: "set null" }),
  industryAiReviewedAt: timestamp("industry_ai_reviewed_at"),
  industryAiStatus: industryAIStatusEnum("industry_ai_status"),
  annualRevenue: numeric("annual_revenue"),
  // Removed precision to allow deployment
  minAnnualRevenue: numeric("min_annual_revenue"),
  // Range minimum for revenue
  maxAnnualRevenue: numeric("max_annual_revenue"),
  // Range maximum for revenue
  revenueRange: revenueRangeEnum("revenue_range"),
  // Pivotal Template: "$500M - $1B", "$1B+", etc.
  employeesSizeRange: staffCountRangeEnum("employees_size_range"),
  // Pivotal Template: "501-1000", "10000+", etc.
  staffCount: integer("staff_count"),
  minEmployeesSize: integer("min_employees_size"),
  // Range minimum for employees
  maxEmployeesSize: integer("max_employees_size"),
  // Range maximum for employees
  description: text("description"),
  // Multiline text with UTF-8 support
  list: text("list"),
  // Source list identifier (e.g., "InFynd", "ZoomInfo")
  // Pivotal B2B Standard Template - Company Location Fields
  hqStreet1: text("hq_street_1"),
  hqStreet2: text("hq_street_2"),
  hqStreet3: text("hq_street_3"),
  hqAddress: text("hq_address"),
  // Legacy combined address
  hqCity: text("hq_city"),
  hqState: text("hq_state"),
  hqStateAbbr: text("hq_state_abbr"),
  // State abbreviation (e.g., "NC", "CA")
  hqPostalCode: text("hq_postal_code"),
  hqCountry: text("hq_country"),
  companyLocation: text("company_location"),
  // Formatted: "5420 Wade Park Boulevard, Raleigh, NC 27607, United States"
  yearFounded: integer("year_founded"),
  foundedDate: date("founded_date"),
  // NEW: YYYY-MM-DD or YYYY only
  foundedDatePrecision: text("founded_date_precision"),
  // NEW: 'year' or 'full'
  sicCode: text("sic_code"),
  naicsCode: text("naics_code"),
  domain: text("domain"),
  domainNormalized: text("domain_normalized"),
  websiteDomain: text("website_domain"),
  // NEW: Normalized naked domain (e.g., aircanada.com)
  previousNames: text("previous_names").array(),
  linkedinUrl: text("linkedin_url"),
  linkedinId: text("linkedin_id"),
  // LinkedIn numeric ID
  linkedinSpecialties: text("linkedin_specialties").array(),
  mainPhone: text("main_phone"),
  mainPhoneE164: text("main_phone_e164"),
  mainPhoneExtension: text("main_phone_extension"),
  intentTopics: text("intent_topics").array(),
  techStack: text("tech_stack").array(),
  webTechnologies: text("web_technologies"),
  // NEW: BuiltWith URL or comma-separated list
  webTechnologiesJson: jsonb("web_technologies_json"),
  // NEW: Normalized array for filtering
  parentAccountId: varchar("parent_account_id"),
  tags: text("tags").array(),
  ownerId: varchar("owner_id").references(() => users.id),
  customFields: jsonb("custom_fields"),
  sourceSystem: text("source_system"),
  sourceRecordId: text("source_record_id"),
  sourceUpdatedAt: timestamp("source_updated_at"),
  // AI-Powered Account Enrichment & Verification
  aiEnrichmentData: jsonb("ai_enrichment_data"),
  // Full AI research results
  aiEnrichmentDate: timestamp("ai_enrichment_date"),
  // Last enrichment timestamp
  // Email Deliverability Score (Account-Level Aggregation)
  emailDeliverabilityScore: numeric("email_deliverability_score", { precision: 5, scale: 2 }),
  // 0-100 score based on contact email validation
  emailDeliverabilityUpdatedAt: timestamp("email_deliverability_updated_at"),
  // Last score calculation timestamp
  // Companies House Validation Cache (Annual Refresh)
  chValidatedAt: timestamp("ch_validated_at"),
  // Last validation timestamp (365-day TTL)
  chValidationStatus: text("ch_validation_status"),
  // 'validated', 'not_found', 'api_error', null
  chCompanyNumber: text("ch_company_number"),
  // UK Companies House registration number
  chLegalName: text("ch_legal_name"),
  // Official registered company name
  chStatus: text("ch_status"),
  // Company status: 'active', 'dissolved', etc.
  chIsActive: boolean("ch_is_active"),
  // True if status is 'active'
  chDateOfCreation: date("ch_date_of_creation"),
  // Company incorporation date
  chAddress: jsonb("ch_address"),
  // Full registered address object
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow()
}, (table) => ({
  domainIdx: index("accounts_domain_idx").on(table.domain),
  domainNormalizedUniqueIdx: uniqueIndex("accounts_domain_normalized_unique_idx").on(table.domainNormalized),
  nameCityCountryUniqueIdx: uniqueIndex("accounts_name_city_country_unique_idx").on(table.nameNormalized, table.hqCity, table.hqCountry).where(sql`domain_normalized IS NULL`),
  ownerIdx: index("accounts_owner_idx").on(table.ownerId),
  nameIdx: index("accounts_name_idx").on(table.name),
  canonicalNameIdx: index("accounts_canonical_name_idx").on(table.canonicalName),
  specialtiesGinIdx: index("accounts_specialties_gin_idx").using("gin", table.linkedinSpecialties),
  techStackGinIdx: index("accounts_tech_stack_gin_idx").using("gin", table.techStack),
  tagsGinIdx: index("accounts_tags_gin_idx").using("gin", table.tags),
  parentAccountFk: foreignKey({
    columns: [table.parentAccountId],
    foreignColumns: [table.id],
    name: "accounts_parent_account_id_fkey"
  }).onDelete("set null")
}));
