  variantName: text("variant_name").notNull(),
  // e.g., "aggressive", "consultative", "educational"
  perspective: promptPerspectiveEnum("perspective").notNull(),
  systemPrompt: text("system_prompt").notNull(),
  firstMessage: text("first_message"),
  context: jsonb("context"),
  // Store generation context: {goal, tone, targetAudience, ...}
  isActive: boolean("is_active").notNull().default(true),
  isDefault: boolean("is_default").notNull().default(false),
  // Scope level: 'account', 'campaign', 'agent'
  variantScope: text("variant_scope").notNull().default("campaign"),
  // Performance tracking
  testResults: jsonb("test_results"),
  // {successRate, engagementScore, callDuration, sampleSize, notes}
