  virtualAgentId: varchar("virtual_agent_id").references(() => virtualAgents.id, { onDelete: "cascade" }).notNull(),
  campaignId: varchar("campaign_id").references(() => campaigns.id, { onDelete: "cascade" }),
  // Assembled prompt layers
