var googleCloudAccounts = pgTable("google_cloud_accounts", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  // Display
  name: varchar("name", { length: 100 }).notNull(),
  // e.g. "Production GCP", "Backup GCP"
  description: text("description"),
  // GCP identity
  projectId: varchar("project_id", { length: 100 }).notNull(),
  location: varchar("location", { length: 50 }).notNull().default("us-central1"),
  gcsBucket: varchar("gcs_bucket", { length: 100 }).notNull(),
  // Gemini / AI API keys (stored plaintext — same security posture as .env)
  geminiApiKey: text("gemini_api_key"),
  // AI Studio key (for Gemini Live)
  googleSearchApiKey: text("google_search_api_key"),
  googleSearchEngineId: varchar("google_search_engine_id", { length: 50 }),
  // OAuth credentials (same OAuth app or different)
  googleClientId: varchar("google_client_id", { length: 150 }),
  googleClientSecret: varchar("google_client_secret", { length: 100 }),
  googleOauthRedirectUri: varchar("google_oauth_redirect_uri", { length: 255 }),
  // Service account — stored as encrypted JSON blob
  serviceAccountJson: text("service_account_json"),
  // AES-256 encrypted JSON
  serviceAccountEmail: varchar("service_account_email", { length: 255 }),
  // for display only
  // State
  isActive: boolean("is_active").notNull().default(false),
  isDefault: boolean("is_default").notNull().default(false),
  // Pool configuration — controls how this account participates in the Gemini key pool
  poolEnabled: boolean("pool_enabled").notNull().default(true),
  // include in voice call pool
  poolRole: varchar("pool_role", { length: 20 }).notNull().default("api_only"),
  // "host" = VM+infra, "api_only" = Gemini API only, "full" = both
  poolMaxSessions: integer("pool_max_sessions").notNull().default(20),
  // max concurrent voice sessions for this account
  poolPriority: integer("pool_priority").notNull().default(0),
  // higher = preferred (0 = equal weight)
  // Multi-cloud: VM can run on any cloud, GCP accounts only provide AI APIs
  vmProvider: varchar("vm_provider", { length: 20 }).default("gcp"),
  // "gcp" | "aws" | "azure" | "bare_metal" — where VM runs
  vmIp: varchar("vm_ip", { length: 45 }),
  // VM external IP (if this account hosts a VM)
  vmRegion: varchar("vm_region", { length: 50 }),
  // VM region (e.g. "us-east-1" for AWS, "eastus" for Azure)
  // Health / last switch
  lastActivatedAt: timestamp("last_activated_at", { withTimezone: true }),
  lastActivatedBy: varchar("last_activated_by", { length: 36 }),
  lastHealthCheckAt: timestamp("last_health_check_at", { withTimezone: true }),
  lastHealthStatus: varchar("last_health_status", { length: 20 }),
  // ok | error | unknown
  lastHealthError: text("last_health_error"),
  // Audit
  createdBy: varchar("created_by", { length: 36 }),
  updatedBy: varchar("updated_by", { length: 36 }),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).notNull().defaultNow()
}, (table) => ({
  activeIdx: index("gca_active_idx").on(table.isActive),
  projectIdx: index("gca_project_idx").on(table.projectId)
}));
